// === ALAN THE MEXICAN - Game Engine ===
// Usage: include this script in any HTML page
// It will create its own canvas and UI elements

(function(){
'use strict';

// --- DOM Setup ---
const style=document.createElement('style');
style.textContent=`
@import url('https://fonts.googleapis.com/css2?family=Press+Start+2P&display=swap');
*{margin:0;padding:0;box-sizing:border-box}
body{background:#0a0a0f;display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;font-family:'Press Start 2P',monospace;color:#c0c0c0;overflow:hidden}
#alan-canvas{border:2px solid #2a2a3a;border-radius:4px;background:linear-gradient(180deg,#1a1a2e 0%,#16213e 40%,#0f3460 100%);box-shadow:0 0 30px rgba(15,52,96,.4),inset 0 0 60px rgba(0,0,0,.3)}
.alan-hud{display:flex;gap:32px;margin-top:16px;font-size:9px;letter-spacing:1px;opacity:.7}
.alan-hud span{color:#5eead4}
.alan-keys{margin-top:20px;font-size:7px;line-height:2;text-align:center;opacity:.4}
.alan-keys kbd{background:#1e1e2e;border:1px solid #3a3a4a;border-radius:3px;padding:2px 6px;margin:0 2px}`;
document.head.appendChild(style);

const wrap=document.createElement('div');
wrap.innerHTML=`
<canvas id="alan-canvas" width="960" height="480"></canvas>
<div class="alan-hud">
  <div>STATE: <span id="alan-s">idle</span></div>
  <div>VEL X: <span id="alan-vx">0</span></div>
  <div>VEL Y: <span id="alan-vy">0</span></div>
  <div>FRAME: <span id="alan-fr">0</span></div>
</div>
<div class="alan-keys">
  <kbd>←</kbd><kbd>→</kbd> Move | <kbd>SPACE</kbd> Jump | <kbd>↓</kbd> Crouch/Crawl | <kbd>Z</kbd> Attack | <kbd>C</kbd> Chilli | <kbd>X</kbd> Die/Reset
</div>`;
document.body.appendChild(wrap);

// --- Frame Data ---
// [x, y, w, h] or [x, y, w, h, 1] where 1 = flipped
// Coordinates for cropped spritesheet (offset -51, -91 from original)
const F={
  idle:[[13,0,58,139],[116,0,58,138],[223,0,58,139],[330,0,58,138]],
  run:[[437,1,71,137],[544,6,75,111],[651,8,72,126],[750,10,101,126],[885,12,101,124],[1008,10,87,126],[1126,11,95,125]],
  jump:[[750,10,101,126]],
  crouch:[[15,184,72,97,1],[231,192,67,90],[420,199,68,83]],
  crawl:[[0,344,114,68],[158,345,114,67],[333,336,106,75],[497,336,103,75],[660,335,106,76],[820,336,107,75]],
  ladder:[[975,304,66,110],[1089,304,59,126]],
  attack:[[346,467,60,135],[473,466,60,136],[590,471,94,128],[473,466,60,136],[346,467,60,135]],
  throw:[[346,467,60,135],[473,466,60,136],[590,471,94,128],[346,467,60,135]],
  death:[[728,537,137,49]]
};

// Animation config: [fps, loop, nativeFacesRight]
const A={
  idle:[8,1,1],run:[14,1,1],jump:[10,0,1],
  crouch:[10,0,0],crawl:[11,1,0],ladder:[6,1,0],
  attack:[14,0,0],throw:[16,0,0],death:[1,0,0]
};

// --- Canvas & Sprite ---
const canvas=document.getElementById('alan-canvas');
const ctx=canvas.getContext('2d');
const img=new Image();
img.src='data:image/png;base64,';

// --- HUD Elements ---
const $s=document.getElementById('alan-s');
const $vx=document.getElementById('alan-vx');
const $vy=document.getElementById('alan-vy');
const $fr=document.getElementById('alan-fr');

// --- Input ---
const keys={};
window.addEventListener('keydown',e=>{keys[e.code]=1;if('ArrowUp ArrowDown ArrowLeft ArrowRight Space'.includes(e.code))e.preventDefault()});
window.addEventListener('keyup',e=>{keys[e.code]=0});

// --- Constants ---
const G=1.2,SPD=10,CSPD=5,JF=-16,GY=canvas.height-60,FR=.82,SC=1.4;

// --- Player State ---
const p={x:canvas.width/2,y:GY,vx:0,vy:0,fr:1,st:'idle',af:0,at:0,ad:0,gnd:1,dead:0,wasGnd:1};

// --- Chilli Projectiles ---
const jals=[];
let throwCD=0;
const THROW_CD=.25,JAL_SPD=15,JAL_GRAV=.12,JAL_SPIN=14;

// --- Audio Engine ---
let ax=null;
function initAudio(){if(!ax)ax=new(window.AudioContext||window.webkitAudioContext)();if(ax.state==='suspended')ax.resume()}

function noise(dur,vol,freq,decay){
  if(!ax)return;
  const t=ax.currentTime,buf=ax.createBuffer(1,ax.sampleRate*dur,ax.sampleRate),d=buf.getChannelData(0);
  for(let i=0;i<d.length;i++)d[i]=(Math.random()*2-1)*Math.exp(-i/(ax.sampleRate*decay));
  const src=ax.createBufferSource(),g=ax.createGain(),f=ax.createBiquadFilter();
  f.type='lowpass';f.frequency.value=freq;
  src.buffer=buf;g.gain.setValueAtTime(vol,t);g.gain.exponentialRampToValueAtTime(.001,t+dur);
  src.connect(f);f.connect(g);g.connect(ax.destination);src.start(t)
}

function tone(freq,dur,vol,type,slide){
  if(!ax)return;
  const t=ax.currentTime,o=ax.createOscillator(),g=ax.createGain();
  o.type=type||'square';o.frequency.setValueAtTime(freq,t);
  if(slide)o.frequency.exponentialRampToValueAtTime(slide,t+dur);
  g.gain.setValueAtTime(vol,t);g.gain.exponentialRampToValueAtTime(.001,t+dur);
  o.connect(g);g.connect(ax.destination);o.start(t);o.stop(t+dur)
}

function sfxJump(){tone(200,.15,.12,'square',500)}
function sfxLand(){noise(.08,.2,400,.03)}
function sfxStep(){noise(.04,.06,800+Math.random()*400,.015)}
function sfxCrawlStep(){noise(.05,.04,500+Math.random()*200,.02)}
function sfxAttack(frame){
  if(frame===1)noise(.12,.18,2000,.04);
  if(frame===2){noise(.08,.22,600,.02);tone(80,.1,.1,'sawtooth',40)}
}
function sfxCrouch(){noise(.06,.08,300,.025)}
function sfxDeath(){tone(300,.4,.15,'sawtooth',50);noise(.3,.12,400,.15)}
function sfxThrow(){tone(500,.06,.1,'square',900);noise(.05,.07,3500,.015)}

// --- Chilli Functions ---
function throwJal(){
  if(throwCD>0||p.dead||p.st==='throw'||p.st==='attack')return;
  throwCD=THROW_CD;
  set('throw');
}

function updJals(dt){
  throwCD=Math.max(0,throwCD-dt);
  for(let i=jals.length-1;i>=0;i--){
    const s=jals[i];
    s.x+=s.vx;s.y+=s.vy;s.vy+=JAL_GRAV;
    s.rot+=JAL_SPIN*dt*(s.vx>0?1:-1);
    s.life-=dt;
    if(s.y>GY-5){s.y=GY-5;s.vy*=-.4;s.vx*=.6;if(Math.abs(s.vy)<1)s.vy=0}
    if(s.life<=0||s.x<-50||s.x>canvas.width+50)jals.splice(i,1)
  }
}

function drawJal(s){
  ctx.save();
  ctx.translate(s.x,s.y);
  ctx.rotate(s.rot);
  ctx.beginPath();
  ctx.moveTo(-2,-16);
  ctx.bezierCurveTo(4,-14,8,-8,10,-2);
  ctx.bezierCurveTo(11,4,10,10,6,16);
  ctx.bezierCurveTo(4,18,2,19,1,18);
  ctx.bezierCurveTo(-2,14,-6,6,-7,-2);
  ctx.bezierCurveTo(-7,-8,-5,-14,-2,-16);
  ctx.fillStyle='#cc1a1a';ctx.fill();
  ctx.strokeStyle='#8b0000';ctx.lineWidth=1;ctx.stroke();
  ctx.beginPath();
  ctx.moveTo(0,-13);
  ctx.bezierCurveTo(4,-10,7,-5,8,0);
  ctx.bezierCurveTo(9,6,7,12,5,15);
  ctx.bezierCurveTo(3,12,2,6,2,0);
  ctx.bezierCurveTo(2,-5,1,-10,0,-13);
  ctx.fillStyle='#e83030';ctx.fill();
  ctx.beginPath();
  ctx.ellipse(3,-5,2,5,-.2,0,Math.PI*2);
  ctx.fillStyle='rgba(255,120,100,.3)';ctx.fill();
  ctx.beginPath();
  ctx.ellipse(4,14,1.5,2,.3,0,Math.PI*2);
  ctx.fillStyle='rgba(255,80,60,.25)';ctx.fill();
  ctx.beginPath();
  ctx.moveTo(-2,-16);
  ctx.bezierCurveTo(-3,-19,-5,-22,-4,-24);
  ctx.bezierCurveTo(-2,-23,0,-21,1,-18);
  ctx.bezierCurveTo(1,-17,0,-16,-2,-16);
  ctx.fillStyle='#3a7a2a';ctx.fill();
  ctx.strokeStyle='#2a5a1a';ctx.lineWidth=.8;ctx.stroke();
  ctx.beginPath();
  ctx.ellipse(-1,-16,4,2,.1,0,Math.PI*2);
  ctx.fillStyle='#4a8c2a';ctx.fill();
  ctx.restore();
}

// --- State Machine ---
let stepTimer=0;

function set(s){
  if(p.st===s)return;
  p.st=s;p.af=0;p.at=0;p.ad=0;stepTimer=0;
  initAudio();
  if(s==='jump')sfxJump();
  if(s==='crouch')sfxCrouch();
  if(s==='death')sfxDeath();
  if(s==='attack')sfxAttack(0);
  if(s==='throw')sfxThrow();
}

function rst(){p.x=canvas.width/2;p.y=GY;p.vx=0;p.vy=0;p.dead=0;p.gnd=1;p.wasGnd=1;set('idle')}

// --- Update ---
function upd(){
  if(p.dead){if(keys.KeyX)rst();return}
  if(keys.KeyX){set('death');p.dead=1;p.vx=0;return}
  if(keys.KeyC)throwJal();
  if(keys.KeyZ&&p.gnd&&p.st!=='attack'&&p.st!=='throw'){set('attack');p.vx=0;return}
  if(p.st==='attack'){if(!p.ad)return}
  if(p.st==='throw'){if(!p.ad)return}
  if(!p.gnd){
    set('jump');
    if(keys.ArrowLeft){p.vx=-SPD;p.fr=0}
    if(keys.ArrowRight){p.vx=SPD;p.fr=1}
    return
  }
  if(keys.ArrowDown){
    if(keys.ArrowLeft||keys.ArrowRight){
      set('crawl');p.vx=keys.ArrowLeft?-CSPD:CSPD;p.fr=p.vx>0?1:0
    }else{set('crouch');p.vx*=FR}
    return
  }
  if(keys.Space&&p.gnd){p.vy=JF;p.gnd=0;set('jump');return}
  if(keys.ArrowLeft||keys.ArrowRight){
    if(keys.ArrowLeft){p.vx=-SPD;p.fr=0}
    if(keys.ArrowRight){p.vx=SPD;p.fr=1}
    set('run');return
  }
  p.vx*=FR;if(Math.abs(p.vx)<.3)p.vx=0;set('idle')
}

// --- Physics ---
function phys(){
  if(p.dead)return;
  if(!p.gnd)p.vy+=G;
  p.x+=p.vx;p.y+=p.vy;
  if(p.y>=GY){
    p.y=GY;p.vy=0;
    if(!p.gnd){initAudio();sfxLand()}
    p.gnd=1
  }
  if(p.x<-80)p.x=canvas.width+40;
  if(p.x>canvas.width+80)p.x=-40
}

// --- Animation ---
function anim(dt){
  const a=A[p.st],f=F[p.st];
  if(!a||!f)return;
  p.at+=dt;
  if(p.at>=1/a[0]){
    p.at-=1/a[0];
    const prevF=p.af;
    p.af++;
    if(p.af>=f.length){if(a[1])p.af=0;else{p.af=f.length-1;p.ad=1}}
    if(p.st==='attack'&&p.af!==prevF){initAudio();sfxAttack(p.af)}
    if(p.st==='throw'&&p.af===2&&prevF===1){
      jals.push({
        x:p.x+(p.fr?30:-30),y:p.y-85,
        vx:p.fr?JAL_SPD:-JAL_SPD,vy:-2.5,
        rot:0,life:3
      })
    }
  }
  if(p.st==='run'){
    stepTimer+=dt;
    if(stepTimer>.14){stepTimer=0;initAudio();sfxStep()}
  }
  if(p.st==='crawl'){
    stepTimer+=dt;
    if(stepTimer>.22){stepTimer=0;initAudio();sfxCrawlStep()}
  }
}

// --- Render ---
function draw(){
  const gy=GY;
  // Ground
  ctx.fillStyle='#0d1117';ctx.fillRect(0,gy,canvas.width,canvas.height-gy);
  ctx.strokeStyle='#1e3a5f';ctx.lineWidth=2;ctx.beginPath();ctx.moveTo(0,gy);ctx.lineTo(canvas.width,gy);ctx.stroke();
  ctx.strokeStyle='rgba(30,58,95,.25)';ctx.lineWidth=1;
  for(let x=0;x<canvas.width;x+=48){ctx.beginPath();ctx.moveTo(x,gy);ctx.lineTo(x,canvas.height);ctx.stroke()}
  // Player
  const a=A[p.st],f=F[p.st];
  if(!a||!f||!f[p.af]||!img.complete)return;
  const d=f[p.af],w=d[2]*SC,h=d[3]*SC,dx=p.x-w/2,dy=p.y-h;
  ctx.save();
  let nfr=a[2];if(d[4])nfr=nfr?0:1;
  if(p.fr!==nfr){ctx.translate(p.x,0);ctx.scale(-1,1);ctx.translate(-p.x,0)}
  ctx.drawImage(img,d[0],d[1],d[2],d[3],dx,dy,w,h);
  ctx.restore();
  // Chillis
  for(const s of jals)drawJal(s);
  // HUD
  $s.textContent=p.st;$vx.textContent=p.vx.toFixed(1);$vy.textContent=p.vy.toFixed(1);$fr.textContent=p.af
}

// --- Game Loop ---
let lt=0;
function loop(ts){
  const dt=Math.min((ts-lt)/1e3,.05);
  lt=ts;
  upd();phys();anim(dt);updJals(dt);
  ctx.clearRect(0,0,canvas.width,canvas.height);
  draw();
  requestAnimationFrame(loop)
}
img.onload=()=>requestAnimationFrame(loop);

})();
